/*
 * cosf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly cosf  (test_cosf_opt.elf)
 *   2. Linked with toolchain's default cosf        (test_cosf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += cosf(vx);
#else
    float r = cosf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 hand-picked inputs                    */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN);                /* smallest normal: 2^-126 = 0x00800000 */
    emit(-FLT_MIN);
    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    emit_u(0x7f7fffffu);          /* FLT_MAX */
    emit_u(0xff7fffffu);          /* -FLT_MAX */
    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 (floating-point density) (8) --- */
    emit_u(0x3f7fffffu);          /* one ULP below 1.0 */
    emit(1.0f);
    emit_u(0x3f800001u);          /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);          /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);          /* a few ULPs above 1.0 */
    emit(-1.0f);
    emit_u(0xbf7fffffu);          /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u);          /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3effffffu);          /* one ULP below 0.5 */
    emit(0.5f);                   /* 0x3f000000 */
    emit_u(0x3f000001u);          /* one ULP above 0.5 */
    emit_u(0x3fffffffu);          /* one ULP below 2.0 */
    emit(2.0f);                   /* 0x40000000 */
    emit_u(0x40000001u);          /* one ULP above 2.0 */

    /* --- Section 6: Pi-grid canonical angles (14) --- */
    emit_u(0x3f060a92u);          /* pi/6: cos = sqrt(3)/2 */
    emit_u(0x3f490fdbu);          /* pi/4: cos = sqrt(2)/2 */
    emit_u(0x3f860a92u);          /* pi/3: cos = 0.5 */
    emit_u(0x3fc90fdbu);          /* pi/2: cos = 0 */
    emit_u(0x3fa8279bu);          /* 2pi/3 */
    emit_u(0x3fb6cbe4u);          /* 3pi/4 */
    emit_u(0x3fc3b346u);          /* 5pi/6 */
    emit_u(0x40490fdbu);          /* pi: cos = -1 */
    emit_u(0x4096cbe4u);          /* 3pi/2: cos = 0 */
    emit_u(0x40c90fdbu);          /* 2pi: cos = 1 */
    emit_u(0xbf490fdbu);          /* -pi/4 */
    emit_u(0xbfc90fdbu);          /* -pi/2 */
    emit_u(0xc0490fdbu);          /* -pi */
    emit_u(0xc0c90fdbu);          /* -2pi */

    /* --- Section 7: Argument reduction stress (8) --- */
    emit_u(0x4b400000u);          /* 12582912.0 = 4*2^21, near pi multiple */
    emit_u(0x4dc90fdbu);          /* ~100*pi as float */
    emit_u(0x501b74eeu);          /* ~1000*pi as float */
    emit(1.0e7f);
    emit(1.0e10f);
    emit(-1.0e7f);
    emit(-1.0e10f);
    emit_u(0x4b000000u);          /* 2^23: mantissa precision boundary */

    /* --- Section 8: ULP neighbors of key trig boundaries (15) --- */
    /* triplet around pi/2: 0x3fc90fdb */
    emit_u(0x3fc90fdau);          /* one ULP below pi/2 */
    emit_u(0x3fc90fdbu);          /* pi/2 */
    emit_u(0x3fc90fdcu);          /* one ULP above pi/2 */
    /* triplet around pi: 0x40490fdb */
    emit_u(0x40490fdau);          /* one ULP below pi */
    emit_u(0x40490fdbu);          /* pi */
    emit_u(0x40490fdcu);          /* one ULP above pi */
    /* triplet around 3pi/2: 0x4096cbe4 */
    emit_u(0x4096cbe3u);          /* one ULP below 3pi/2 */
    emit_u(0x4096cbe4u);          /* 3pi/2 */
    emit_u(0x4096cbe5u);          /* one ULP above 3pi/2 */
    /* triplet around 2pi: 0x40c90fdb */
    emit_u(0x40c90fdau);          /* one ULP below 2pi */
    emit_u(0x40c90fdbu);          /* 2pi */
    emit_u(0x40c90fdcu);          /* one ULP above 2pi */
    /* triplet around -pi/2: 0xbfc90fdb */
    emit_u(0xbfc90fdau);          /* one ULP toward zero from -pi/2 */
    emit_u(0xbfc90fdbu);          /* -pi/2 */
    emit_u(0xbfc90fdcu);          /* one ULP away from zero from -pi/2 */

    /* --- Section 9: Small-argument fast-path boundaries (8) --- */
    emit_u(0x39800000u);          /* 2^-12: lower bound of linear region */
    emit_u(0xb9800000u);          /* -2^-12 */
    emit_u(0x3c000000u);          /* 2^-7 */
    emit_u(0xbc000000u);          /* -2^-7 */
    emit_u(0x3a800000u);          /* 2^-10 */
    emit_u(0xba800000u);          /* -2^-10 */
    emit_u(0x33800000u);          /* 2^-24: one-ULP magnitude for float */
    emit_u(0xb3800000u);          /* -2^-24 */

    /* --- Section 10: Polynomial branch and hard reduction cases (22) --- */
    /* triplet around pi/8: 0x3ec90fdb */
    emit_u(0x3ec90fdau);          /* one ULP below pi/8 */
    emit_u(0x3ec90fdbu);          /* pi/8 */
    emit_u(0x3ec90fdcu);          /* one ULP above pi/8 */
    /* triplet around pi/4: 0x3f490fdb */
    emit_u(0x3f490fdau);          /* one ULP below pi/4 */
    emit_u(0x3f490fdbu);          /* pi/4 */
    emit_u(0x3f490fdcu);          /* one ULP above pi/4 */
    /* 3pi/8 and -3pi/8: exercises cos-path reconstruction */
    emit_u(0x3f96cbe4u);          /* 3pi/8 */
    emit_u(0xbf96cbe4u);          /* -3pi/8 */
    /* k*pi for k = 3, 4, 5 (cos ~ +-1, cancellation stress) */
    emit_u(0x40db4510u);          /* 3*pi */
    emit_u(0x41490fdbu);          /* 4*pi */
    emit_u(0x419cb27fu);          /* 5*pi */
    /* odd half-multiples: 5pi/2, 7pi/2, -5pi/2 (cos = 0 after reduction) */
    emit_u(0x40f6cbe4u);          /* 5pi/2 */
    emit_u(0x4116cbe4u);          /* 7pi/2 */
    emit_u(0xc0f6cbe4u);          /* -5pi/2 */
    /* non-pi normals */
    emit(3.0f);
    emit(-3.0f);
    /* large int multiples of pi (catastrophic reduction) */
    emit_u(0x461c9c3au);          /* 10*pi as float */
    emit_u(0x48c90fdbu);          /* 100000*pi approximation */
    /* scaled pi/2 patterns at 2^23 magnitude (Payne-Hanek stress) */
    emit_u(0x4b490fdbu);          /* 2^23 * (pi/2 normalized) */
    emit_u(0x4bc90fdbu);          /* 2^24 * pi/2 */
    /* additional hard-rounded float */
    emit_u(0x4a7d6857u);          /* known hard cosf reduction case */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 4*pi] and [-4*pi, 0] in 200 steps each */
static void test_sweep(void)
{
    float hi = 4.0f * 3.14159265358979323846f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    /* [0, 4*pi] */
    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    /* [-4*pi, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* 8. Sample [0, pi/4] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f490fdbu; /* pi/4 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
/*
 * perf(x) -- exercise the hot kernel path N times and print the result.
 *
 * Critical path for cosf():
 *   __gf_fpreduct  (argument reduction)
 *   -> __gf_exmul  (extended-precision multiply)
 *   -> __gf_sigmax(__gf_fpcoscof, degree 5)  (polynomial kernel)
 *   -> __gf_exmul  (scale result)
 *
 * This path is taken when the reduced quadrant index q satisfies
 * (q-1)&2 == 0, i.e. q == 1 or q == 2.  x = 1.0 falls in quadrant 0.
 */
static void perf(float x)
{
    volatile float acc = 0.0f;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += cosf(x+i);
    stopPFM;
    readResult();
    printf("perf %08lx: %08lx\n",
           (unsigned long)f2u(x),
           (unsigned long)f2u((float)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.0f); /* quadrant 0: hits cos-polynomial kernel path */
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

